actions.script:
// Fetch the exact bridge record using composite PK
def link = ec.entity.find("tutorial.party.PartyContactMech")
    .condition("partyId", partyId)
    .condition("contactMechId", contactMechId)
    .condition("fromDate", fromDate)
    .one()

if (link != null) {
    // Setting thruDate = now marks it as "no longer active"
    link.set("thruDate", ec.user.nowTimestamp)
    link.update()
    ec.logger.info("Deactivated contact " + contactMechId + " for party " + partyId)
} else {
    ec.message.addError("Contact record not found.")
}

// Fetch the exact bridge record using its composite PK
def link = ec.entity.find("tutorial.party.PartyContactMech")
    .condition("partyId", partyId)
    .condition("contactMechId", contactMechId)
    .condition("fromDate", fromDate)
    .one()

if (link != null) {
    // Setting thruDate = null marks it as "active again"
    link.set("thruDate", null)
    link.update()
    ec.logger.info("Reactivated contact " + contactMechId + " for party " + partyId)
} else {
    ec.message.addError("Contact record not found.")
}

def existing = ec.entity.find("tutorial.party.PartyRelationship") .condition("fromPartyId", fromPartyId) .condition("toPartyId", toPartyId) .condition("roleTypeId", roleTypeId) .condition("thruDate", null) .one()
if (existing) { ec.message.addError("This relationship is already active!") return }
def newRel = ec.entity.makeValue("tutorial.party.PartyRelationship") newRel.setAll(context) newRel.set("fromDate", ec.user.nowTimestamp) newRel.create()
ec.logger.info("Created relationship: " + fromPartyId + " -> " + toPartyId)

def rel = ec.entity.find("tutorial.party.PartyRelationship")
    .condition("fromPartyId", fromPartyId)
    .condition("toPartyId", toPartyId)
    .condition("roleTypeId", roleTypeId)
    .condition("fromDate", fromDate)
    .one()

if (rel != null) {
    rel.set("thruDate", ec.user.nowTimestamp)
    rel.update()
} else {
    ec.message.addError("Relationship not found.")
}
